INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e3616cab-d8a6-416c-8483-70f587de10aa',
  '00000000-0000-0000-0000-000000000001',
  $escape$pandas df.describe() Is Not Enough — Profile Your Data in 5 Lines$escape$,
  $escape$Most pandas users stop at df.describe(), but it only covers numeric columns and tells you nothing about missing values, cardinality, or distribution shape. A proper profiling pass should answer three questions fast: what's missing, what's unique, and what's skewed.

Chain df.info() with df.isnull().sum() to spot dtype mismatches and NaN hotspots. Use df.nunique() to flag columns with suspiciously low cardinality (potential categoricals) or suspiciously high cardinality (potential IDs leaking into features). For distribution shape, df.skew() and df.kurtosis() across numeric columns reveal outlier-heavy tails faster than plotting every histogram.

The real power move: combine these into a single summary DataFrame you can sort and filter. Sorting by null percentage immediately surfaces the columns that need imputation or dropping. Sorting by skew flags candidates for log transforms. This ten-second profiling habit catches data issues that df.describe() silently hides — like a column that's 80% NaN but has a perfectly normal mean.$escape$,
  $escape$import pandas as pd

def profile(df: pd.DataFrame) -> pd.DataFrame:
    return pd.DataFrame({
        "dtype": df.dtypes,
        "nulls": df.isnull().sum(),
        "null_pct": (df.isnull().mean() * 100).round(1),
        "nunique": df.nunique(),
        "skew": df.select_dtypes("number").skew().reindex(df.columns),
        "kurtosis": df.select_dtypes("number").kurtosis().reindex(df.columns),
    }).sort_values("null_pct", ascending=False)

# Usage: profile(pd.read_csv("dataset.csv"))$escape$,
  $escape$python$escape$,
