INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'de9891d6-e31c-48a2-9cd2-e3915297ad15',
  '00000000-0000-0000-0000-000000000001',
  $escape$pandas Feature Engineering — Encode, Scale, Bin, and Interact in One Pipeline$escape$,
  $escape$pd.get_dummies() one-hot encodes categoricals, but for high-cardinality columns it bloats your DataFrame. Use .cat.codes for ordinal encoding or map a frequency table with .map(df['col'].value_counts()). For scaling, avoid sklearn when you can: (df['col'] - df['col'].mean()) / df['col'].std() gives z-scores natively. pd.cut() bins continuous features into discrete intervals — pass labels=False for integer bins usable downstream. pd.qcut() gives equal-frequency bins instead. Interaction features are a one-liner: df['price_per_sqft'] = df['price'] / df['sqft']. For polynomial interactions across multiple columns, combine .assign() with lambda chains. A subtle trick: use .pipe() to compose these steps into a reusable transformation function that takes and returns a DataFrame, keeping your feature engineering reproducible without leaving pandas. Watch memory — call .astype('category') on encoded columns and prefer int8/float32 dtypes via .astype() after binning to keep large DataFrames lean.$escape$,
  $escape$import pandas as pd
import numpy as np

def engineer_features(df: pd.DataFrame) -> pd.DataFrame:
    return (df
        .assign(
            city_encoded=lambda d: d['city'].map(d['city'].value_counts()),
            price_scaled=lambda d: (d['price'] - d['price'].mean()) / d['price'].std(),
            age_bin=lambda d: pd.cut(d['age'], bins=5, labels=False),
            price_per_sqft=lambda d: d['price'] / d['sqft'],
        )
        .astype({'age_bin': 'int8', 'city_encoded': 'int32'})
    )

df = pd.DataFrame({'city': ['NYC','SF','NYC','LA','SF'],
                    'price': [500,800,450,600,750],
                    'sqft': [600,400,550,700,350],
                    'age': [25,34,29,41,22]})
print(engineer_features(df))$escape$,
  $escape$python$escape$,
