INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '807300a5-fa43-415a-a209-5f931de1ef7f',
  '00000000-0000-0000-0000-000000000001',
  $escape$pandas Time Series Toolkit — Resample, Roll, and Lag in 10 Lines$escape$,
  $escape$pandas treats DatetimeIndex as a first-class citizen, unlocking powerful time series ops without reaching for specialized libraries. `resample()` buckets irregular timestamps into fixed intervals — think of it as a time-aware `groupby`. Chain it with `.agg()` to compute multiple stats per window. `rolling()` slides a fixed-size window across your Series, ideal for smoothing noise or computing moving averages. Set `min_periods` to avoid NaN-heavy edges. For ML feature engineering, `shift()` creates lag features instantly — `df['lag_7'] = df['value'].shift(7)` gives you last week's value aligned to today's row. Stack multiple lags with a list comprehension for autoregressive inputs. To capture seasonality, combine `resample('M').mean()` with `diff(12)` for year-over-year deltas, or use `dt.month` to group by calendar cycle. The key insight: keep your index as a proper DatetimeIndex (via `pd.to_datetime`) — every method above depends on it. Without it, you're fighting pandas instead of leveraging it.$escape$,
  $escape$import pandas as pd

df = pd.DataFrame({
    'date': pd.date_range('2023-01-01', periods=365, freq='D'),
    'value': range(365)
}).set_index('date')

# Resample to weekly mean
weekly = df.resample('W').agg(['mean', 'std'])

# 30-day rolling average
df['rolling_30'] = df['value'].rolling(30, min_periods=1).mean()

# Lag features for ML
for lag in [1, 7, 28]:
    df[f'lag_{lag}'] = df['value'].shift(lag)

# Year-over-year seasonality via monthly diff
monthly = df['value'].resample('M').mean()
monthly_yoy = monthly.diff(12)$escape$,
  $escape$python$escape$,
